var COURSE_PL_HI = [{day: 1, title: `Pierwsze powitania`, title_native: `पहली मुलाकात`, focus: `Zaczniesz od najprostszych powitań i zwrotów grzecznościowych przydatnych po przylocie do Delhi lub Mumbaju. Nauczysz się mówić „dzień dobry”, „dziękuję” i krótko reagować w rozmowie.`, vocab: [{hi: `नमस्ते`, pl: `dzień dobry / cześć`, ipa: `/nə-məs-teː/`},{hi: `धन्यवाद`, pl: `dziękuję`, ipa: `/dʱən-jə-vaːd/`},{hi: `हाँ`, pl: `tak`, ipa: `/haːn/`},{hi: `नहीं`, pl: `nie`, ipa: `/nə-hiːn/`},{hi: `कृपया`, pl: `proszę`, ipa: `/krɪ-pə-jaː/`},{hi: `माफ़ कीजिए`, pl: `przepraszam`, ipa: `/maːf kiː-d͡ʒi-je/`},{hi: `जी`, pl: `grzecznościowe „tak”, pan/pani`, ipa: `/d͡ʒiː/`},{hi: `अच्छा`, pl: `dobrze / okej`, ipa: `/ət͡ʃ-t͡ʃʰaː/`},{hi: `फिर मिलेंगे`, pl: `do zobaczenia`, ipa: `/pʰir mɪ-leːŋ-geː/`}], phrases: [{hi: `नमस्ते, आप कैसे हैं?`, pl: `Dzień dobry, jak się pan/pani ma?`, ipa: `/nə-məs-teː aːp kæː-seː hæːn/`},{hi: `मैं ठीक हूँ।`, pl: `Mam się dobrze.`, ipa: `/mæ̃ː ʈʰiːk huːn/`},{hi: `धन्यवाद।`, pl: `Dziękuję.`, ipa: `/dʱən-jə-vaːd/`},{hi: `माफ़ कीजिए।`, pl: `Przepraszam.`, ipa: `/maːf kiː-d͡ʒi-je/`},{hi: `कोई बात नहीं।`, pl: `Nic się nie stało.`, ipa: `/koː-iː baːt nə-hiːn/`},{hi: `फिर मिलेंगे।`, pl: `Do zobaczenia.`, ipa: `/pʰir mɪ-leːŋ-geː/`}], grammar: `W hindi bardzo często używa się grzecznościowego आप, czyli „pan/pani/wy”. W podróży najbezpieczniej zaczynać rozmowę właśnie od आप, szczególnie z obsługą hotelu, kierowcą lub sprzedawcą. Słowo जी dodaje uprzejmości i może pojawić się jako odpowiedź: हाँ जी oznacza grzeczne „tak”.`, practice: [`Powiedz po hindi „Dzień dobry” i „Dziękuję”.`,`Odpowiedz po hindi, że masz się dobrze.`,`Przećwicz grzeczne „tak” i „nie”.`,`Ułóż krótką scenkę: wchodzisz do hotelu w Delhi i witasz recepcjonistę.`,`Powtórz pięć razy माफ़ कीजिए, zwracając uwagę na miękką wymowę końcówki.`]},{day: 2, title: `Przedstawianie się`, title_native: `अपना परिचय देना`, focus: `Nauczysz się mówić, jak masz na imię i skąd jesteś. To przyda się podczas spotkań z mieszkańcami, w hostelu lub na wycieczce grupowej w Jaipurze.`, vocab: [{hi: `मैं`, pl: `ja`, ipa: `/mæ̃ː/`},{hi: `आप`, pl: `pan/pani/ty grzecznie`, ipa: `/aːp/`},{hi: `नाम`, pl: `imię`, ipa: `/naːm/`},{hi: `मेरा`, pl: `mój`, ipa: `/meː-raː/`},{hi: `आपका`, pl: `pana/pani`, ipa: `/aːp-kaː/`},{hi: `पोलैंड`, pl: `Polska`, ipa: `/poː-lɛɳɖ/`},{hi: `भारत`, pl: `Indie`, ipa: `/bʱaː-rət/`},{hi: `से`, pl: `z / od`, ipa: `/seː/`},{hi: `कहाँ`, pl: `gdzie`, ipa: `/kə-haːn/`},{hi: `दोस्त`, pl: `przyjaciel`, ipa: `/doːst/`}], phrases: [{hi: `मेरा नाम अन्ना है।`, pl: `Mam na imię Anna.`, ipa: `/meː-raː naːm an-naː hæː/`},{hi: `आपका नाम क्या है?`, pl: `Jak ma pan/pani na imię?`, ipa: `/aːp-kaː naːm kjaː hæː/`},{hi: `मैं पोलैंड से हूँ।`, pl: `Jestem z Polski.`, ipa: `/mæ̃ː poː-lɛɳɖ seː huːn/`},{hi: `आप कहाँ से हैं?`, pl: `Skąd pan/pani jest?`, ipa: `/aːp kə-haːn seː hæːn/`},{hi: `मैं भारत से हूँ।`, pl: `Jestem z Indii.`, ipa: `/mæ̃ː bʱaː-rət seː huːn/`},{hi: `आपसे मिलकर खुशी हुई।`, pl: `Miło pana/panią poznać.`, ipa: `/aːp-seː mɪl-kər kʰu-ʃiː hu-iː/`}], grammar: `Zdanie „jestem z Polski” buduje się dosłownie jako „ja Polska z jestem”: मैं पोलैंड से हूँ। Czasownik हूँ oznacza „jestem”, a से oznacza „z”. W hindi szyk zdania często jest inny niż w polskim, więc na początku warto uczyć się całych wzorów zdań.`, practice: [`Powiedz po hindi swoje imię.`,`Zapytaj kogoś grzecznie o imię.`,`Powiedz, że jesteś z Polski.`,`Zapytaj „Skąd pan/pani jest?”.`,`Połącz powitanie z przedstawieniem się w jednej krótkiej wypowiedzi.`]},{day: 3, title: `Podstawowe pytania`, title_native: `बुनियादी सवाल`, focus: `Dziś nauczysz się kilku pytań, które pomagają rozpocząć rozmowę w podróży. Będą przydatne na lotnisku w Delhi, przy informacji turystycznej i w hotelu.`, vocab: [{hi: `क्या`, pl: `co / czy`, ipa: `/kjaː/`},{hi: `कहाँ`, pl: `gdzie`, ipa: `/kə-haːn/`},{hi: `कब`, pl: `kiedy`, ipa: `/kəb/`},{hi: `कितना`, pl: `ile`, ipa: `/kɪt-naː/`},{hi: `कौन`, pl: `kto`, ipa: `/koːn/`},{hi: `क्यों`, pl: `dlaczego`, ipa: `/kjoːn/`},{hi: `कैसे`, pl: `jak`, ipa: `/kæː-seː/`},{hi: `यह`, pl: `to`, ipa: `/jəh/`},{hi: `वह`, pl: `tamto / on / ona`, ipa: `/ʋəh/`},{hi: `यहाँ`, pl: `tutaj`, ipa: `/jə-haːn/`}], phrases: [{hi: `यह क्या है?`, pl: `Co to jest?`, ipa: `/jəh kjaː hæː/`},{hi: `यह कहाँ है?`, pl: `Gdzie to jest?`, ipa: `/jəh kə-haːn hæː/`},{hi: `कितना है?`, pl: `Ile to kosztuje?`, ipa: `/kɪt-naː hæː/`},{hi: `आप कैसे हैं?`, pl: `Jak się pan/pani ma?`, ipa: `/aːp kæː-seː hæːn/`},{hi: `यहाँ कहाँ है?`, pl: `Gdzie to jest tutaj?`, ipa: `/jə-haːn kə-haːn hæː/`},{hi: `कब खुलता है?`, pl: `Kiedy się otwiera?`, ipa: `/kəb kʰul-taː hæː/`}], grammar: `Słowo क्या może oznaczać „co”, ale na początku zdania często tworzy pytanie typu „czy”. Na przykład क्या यह होटल है? znaczy „Czy to jest hotel?”. W codziennej rozmowie ton głosu także pomaga rozpoznać pytanie.`, practice: [`Zapytaj po hindi „Co to jest?”.`,`Zapytaj „Gdzie to jest?”.`,`Zapytaj o cenę prostym zwrotem.`,`Zmień zdanie यह होटल है na pytanie z क्या.`,`Wyobraź sobie, że pokazujesz mapę w telefonie i pytasz o miejsce.`]},{day: 4, title: `Liczby od 0 do 20`, title_native: `शून्य से बीस तक नंबर`, focus: `Liczby są potrzebne przy płaceniu, kupowaniu biletów i podawaniu numeru pokoju. Dziś skupisz się na pierwszych dwudziestu liczbach używanych w Indiach.`, vocab: [{hi: `शून्य`, pl: `zero`, ipa: `/ʃuː-njə/`},{hi: `एक`, pl: `jeden`, ipa: `/eːk/`},{hi: `दो`, pl: `dwa`, ipa: `/doː/`},{hi: `तीन`, pl: `trzy`, ipa: `/tiːn/`},{hi: `चार`, pl: `cztery`, ipa: `/t͡ʃaːr/`},{hi: `पाँच`, pl: `pięć`, ipa: `/paːnt͡ʃ/`},{hi: `छह`, pl: `sześć`, ipa: `/t͡ʃʰəh/`},{hi: `सात`, pl: `siedem`, ipa: `/saːt/`},{hi: `आठ`, pl: `osiem`, ipa: `/aːʈʰ/`},{hi: `दस`, pl: `dziesięć`, ipa: `/dəs/`}], phrases: [{hi: `एक चाय, कृपया।`, pl: `Jedną herbatę, proszę.`, ipa: `/eːk t͡ʃaːj krɪ-pə-jaː/`},{hi: `दो टिकट चाहिए।`, pl: `Potrzebuję dwóch biletów.`, ipa: `/doː ʈɪ-kəʈ t͡ʃaː-hi-jeː/`},{hi: `तीन लोग हैं।`, pl: `Są trzy osoby.`, ipa: `/tiːn loːg hæːn/`},{hi: `कमरा नंबर पाँच।`, pl: `Pokój numer pięć.`, ipa: `/kəm-raː nəm-bər paːnt͡ʃ/`},{hi: `दस रुपये।`, pl: `Dziesięć rupii.`, ipa: `/dəs rʊ-pə-jeː/`},{hi: `एक मिनट।`, pl: `Jedna minuta.`, ipa: `/eːk mɪ-nəʈ/`}], grammar: `W hindi rzeczowniki po liczbach często nie zachowują się tak jak w polskim. Możesz powiedzieć दो टिकट चाहिए, dosłownie „dwa bilet potrzebne”, i będzie to naturalne w prostym kontekście podróżnym. Na tym etapie najważniejsze jest szybkie rozpoznawanie liczb.`, practice: [`Policz po hindi od 1 do 10.`,`Zamów jedną herbatę.`,`Poproś o dwa bilety.`,`Powiedz numer pokoju: pięć.`,`Przećwicz rozumienie cen: 10 rupii, 5 rupii, 2 bilety.`]},{day: 5, title: `Uprzejme prośby i pomoc`, title_native: `विनम्र अनुरोध और मदद`, focus: `Nauczysz się prosić o pomoc w sposób uprzejmy i spokojny. To ważne w zatłoczonych miejscach, takich jak stacja kolejowa New Delhi lub bazar w Old Delhi.`, vocab: [{hi: `मदद`, pl: `pomoc`, ipa: `/mə-dəd/`},{hi: `चाहिए`, pl: `potrzeba / chciałbym`, ipa: `/t͡ʃaː-hi-jeː/`},{hi: `कृपया`, pl: `proszę`, ipa: `/krɪ-pə-jaː/`},{hi: `सुनिए`, pl: `proszę posłuchać / przepraszam`, ipa: `/sʊ-ni-jeː/`},{hi: `धीरे`, pl: `wolno / powoli`, ipa: `/dʱiː-reː/`},{hi: `फिर से`, pl: `jeszcze raz`, ipa: `/pʰir seː/`},{hi: `बोलिए`, pl: `proszę mówić`, ipa: `/boː-li-jeː/`},{hi: `समझना`, pl: `rozumieć`, ipa: `/sə-məd͡ʒʱ-naː/`},{hi: `रुकिए`, pl: `proszę poczekać`, ipa: `/rʊ-ki-jeː/`},{hi: `ज़रूर`, pl: `oczywiście`, ipa: `/zə-ruːr/`}], phrases: [{hi: `मुझे मदद चाहिए।`, pl: `Potrzebuję pomocy.`, ipa: `/mʊ-d͡ʒʱeː mə-dəd t͡ʃaː-hi-jeː/`},{hi: `कृपया धीरे बोलिए।`, pl: `Proszę mówić wolniej.`, ipa: `/krɪ-pə-jaː dʱiː-reː boː-li-jeː/`},{hi: `फिर से बोलिए।`, pl: `Proszę powiedzieć jeszcze raz.`, ipa: `/pʰir seː boː-li-jeː/`},{hi: `मैं नहीं समझता।`, pl: `Nie rozumiem.`, ipa: `/mæ̃ː nə-hiːn sə-məd͡ʒʱ-taː/`},{hi: `रुकिए, कृपया।`, pl: `Proszę poczekać.`, ipa: `/rʊ-ki-jeː krɪ-pə-jaː/`},{hi: `क्या आप मदद कर सकते हैं?`, pl: `Czy może pan/pani pomóc?`, ipa: `/kjaː aːp mə-dəd kər sək-teː hæːn/`}], grammar: `Zwrot मुझे ... चाहिए jest bardzo praktyczny i oznacza „potrzebuję...” albo „chciałbym/chciałabym...”. Możesz wstawić rzeczownik: मुझे पानी चाहिए, मुझे टिकट चाहिए, मुझे मदद चाहिए. To jeden z najważniejszych wzorów dla podróżnika.`, practice: [`Powiedz, że potrzebujesz pomocy.`,`Poproś kogoś, by mówił wolniej.`,`Powiedz, że nie rozumiesz.`,`Użyj wzoru मुझे ... चाहिए z trzema rzeczami.`,`Przećwicz scenkę: zgubiłeś się na stacji i prosisz o pomoc.`]},{day: 6, title: `Lotnisko i przyjazd`, title_native: `हवाई अड्डा और आगमन`, focus: `Dziś przygotujesz się do pierwszych chwil po przylocie do Indii. Nauczysz się słów potrzebnych przy bagażu, paszporcie, taksówce i wyjściu z lotniska.`, vocab: [{hi: `हवाई अड्डा`, pl: `lotnisko`, ipa: `/hə-ʋaː-iː əɖ-ɖaː/`},{hi: `पासपोर्ट`, pl: `paszport`, ipa: `/paːs-poːrʈ/`},{hi: `बैग`, pl: `torba / bagaż`, ipa: `/bæːg/`},{hi: `सामान`, pl: `bagaż`, ipa: `/saː-maːn/`},{hi: `टैक्सी`, pl: `taksówka`, ipa: `/ʈɛːk-siː/`},{hi: `निकास`, pl: `wyjście`, ipa: `/nɪ-kaːs/`},{hi: `आगमन`, pl: `przylot / przyjazd`, ipa: `/aː-gə-mən/`},{hi: `प्रस्थान`, pl: `odlot / wyjazd`, ipa: `/prəs-tʰaːn/`},{hi: `कस्टम`, pl: `odprawa celna`, ipa: `/kəs-ʈəm/`},{hi: `सीधा`, pl: `prosto`, ipa: `/siː-dʱaː/`}], phrases: [{hi: `मेरा सामान कहाँ है?`, pl: `Gdzie jest mój bagaż?`, ipa: `/meː-raː saː-maːn kə-haːn hæː/`},{hi: `टैक्सी कहाँ मिलेगी?`, pl: `Gdzie znajdę taksówkę?`, ipa: `/ʈɛːk-siː kə-haːn mɪ-leː-giː/`},{hi: `निकास कहाँ है?`, pl: `Gdzie jest wyjście?`, ipa: `/nɪ-kaːs kə-haːn hæː/`},{hi: `यह मेरा पासपोर्ट है।`, pl: `To jest mój paszport.`, ipa: `/jəh meː-raː paːs-poːrʈ hæː/`},{hi: `मुझे होटल जाना है।`, pl: `Muszę jechać do hotelu.`, ipa: `/mʊ-d͡ʒʱeː hoː-ʈəl d͡ʒaː-naː hæː/`},{hi: `कृपया सीधा चलिए।`, pl: `Proszę jechać prosto.`, ipa: `/krɪ-pə-jaː siː-dʱaː t͡ʃə-li-jeː/`}], grammar: `Czasownik जाना oznacza „iść” lub „jechać” w zależności od kontekstu. Zwrot मुझे होटल जाना है znaczy dosłownie „mnie hotel iść/jechać jest”, czyli „muszę jechać do hotelu”. W podróży możesz używać tego wzoru z nazwami miejsc.`, practice: [`Zapytaj, gdzie jest wyjście.`,`Powiedz, że musisz jechać do hotelu.`,`Zapytaj, gdzie znajdziesz taksówkę.`,`Powiedz „To jest mój paszport”.`,`Ułóż krótką rozmowę z pracownikiem lotniska.`]},{day: 7, title: `Hotel i zameldowanie`, title_native: `होटल में चेक-इन`, focus: `Nauczysz się meldować w hotelu, pytać o rezerwację i numer pokoju. Scena rozgrywa się w recepcji hotelu w Jaipurze.`, vocab: [{hi: `होटल`, pl: `hotel`, ipa: `/hoː-ʈəl/`},{hi: `कमरा`, pl: `pokój`, ipa: `/kəm-raː/`},{hi: `बुकिंग`, pl: `rezerwacja`, ipa: `/bʊ-kɪŋ/`},{hi: `चेक-इन`, pl: `zameldowanie`, ipa: `/t͡ʃek ɪn/`},{hi: `चाबी`, pl: `klucz`, ipa: `/t͡ʃaː-biː/`},{hi: `रिसेप्शन`, pl: `recepcja`, ipa: `/rɪ-sep-ʃən/`},{hi: `नाम`, pl: `imię / nazwisko`, ipa: `/naːm/`},{hi: `आज`, pl: `dziś`, ipa: `/aːd͡ʒ/`},{hi: `कल`, pl: `jutro / wczoraj`, ipa: `/kəl/`},{hi: `रात`, pl: `noc`, ipa: `/raːt/`}], phrases: [{hi: `मेरी बुकिंग है।`, pl: `Mam rezerwację.`, ipa: `/meː-riː bʊ-kɪŋ hæː/`},{hi: `मेरा नाम पिओत्र है।`, pl: `Mam na imię Piotr.`, ipa: `/meː-raː naːm pjoːtr hæː/`},{hi: `मुझे चेक-इन करना है।`, pl: `Chcę się zameldować.`, ipa: `/mʊ-d͡ʒʱeː t͡ʃek ɪn kər-naː hæː/`},{hi: `कमरा नंबर क्या है?`, pl: `Jaki jest numer pokoju?`, ipa: `/kəm-raː nəm-bər kjaː hæː/`},{hi: `क्या नाश्ता शामिल है?`, pl: `Czy śniadanie jest wliczone?`, ipa: `/kjaː naːʃ-taː ʃaː-mɪl hæː/`},{hi: `चाबी दीजिए, कृपया।`, pl: `Proszę dać klucz.`, ipa: `/t͡ʃaː-biː diː-d͡ʒi-jeː krɪ-pə-jaː/`}], grammar: `W hindi zaimki dzierżawcze zmieniają formę podobnie jak przymiotniki. मेरा używa się z rzeczownikami męskimi, a मेरी z żeńskimi, dlatego „mój pokój” to मेरा कमरा, ale „moja rezerwacja” to मेरी बुकिंग. W praktyce obsługa i tak zwykle zrozumie sens, nawet jeśli forma nie będzie idealna.`, practice: [`Powiedz, że masz rezerwację.`,`Podaj swoje imię w zdaniu.`,`Zapytaj o numer pokoju.`,`Zapytaj, czy śniadanie jest wliczone.`,`Odegraj krótkie zameldowanie w hotelu.`]},{day: 8, title: `Kierunki i orientacja`, title_native: `दिशा और रास्ता`, focus: `Dziś nauczysz się pytać o drogę i rozumieć podstawowe wskazówki. To przydatne podczas spaceru po Varanasi, Jaipurze lub dzielnicach Delhi.`, vocab: [{hi: `रास्ता`, pl: `droga`, ipa: `/raːs-taː/`},{hi: `दाएँ`, pl: `w prawo`, ipa: `/daː-ẽː/`},{hi: `बाएँ`, pl: `w lewo`, ipa: `/baː-ẽː/`},{hi: `सीधा`, pl: `prosto`, ipa: `/siː-dʱaː/`},{hi: `पास`, pl: `blisko / przy`, ipa: `/paːs/`},{hi: `दूर`, pl: `daleko`, ipa: `/duːr/`},{hi: `यहाँ`, pl: `tutaj`, ipa: `/jə-haːn/`},{hi: `वहाँ`, pl: `tam`, ipa: `/ʋə-haːn/`},{hi: `बाज़ार`, pl: `bazar`, ipa: `/baː-zaːr/`},{hi: `मंदिर`, pl: `świątynia`, ipa: `/mən-dɪr/`}], phrases: [{hi: `बाज़ार कहाँ है?`, pl: `Gdzie jest bazar?`, ipa: `/baː-zaːr kə-haːn hæː/`},{hi: `सीधा जाइए।`, pl: `Proszę iść prosto.`, ipa: `/siː-dʱaː d͡ʒaː-i-jeː/`},{hi: `दाएँ मुड़िए।`, pl: `Proszę skręcić w prawo.`, ipa: `/daː-ẽː mʊ-ɽi-jeː/`},{hi: `बाएँ मुड़िए।`, pl: `Proszę skręcić w lewo.`, ipa: `/baː-ẽː mʊ-ɽi-jeː/`},{hi: `क्या यह पास है?`, pl: `Czy to jest blisko?`, ipa: `/kjaː jəh paːs hæː/`},{hi: `मंदिर दूर है।`, pl: `Świątynia jest daleko.`, ipa: `/mən-dɪr duːr hæː/`}], grammar: `Tryb grzeczny rozkazujący często kończy się na -इए, jak जाइए, मुड़िए, बोलिए. To forma bezpieczna w rozmowie z nieznajomymi. Gdy prosisz o drogę, możesz połączyć माफ़ कीजिए z pytaniem o miejsce.`, practice: [`Zapytaj, gdzie jest bazar.`,`Powiedz „proszę iść prosto”.`,`Przećwicz „w lewo” i „w prawo”.`,`Zapytaj, czy miejsce jest blisko.`,`Opisz prostą trasę: prosto, potem w lewo.`]},{day: 9, title: `Transport miejski`, title_native: `शहर का यातायात`, focus: `Poznasz słowa i zwroty potrzebne w metrze, autobusie i auto-rikszy. Skupimy się na poruszaniu po Delhi lub Lucknow.`, vocab: [{hi: `मेट्रो`, pl: `metro`, ipa: `/meː-ʈroː/`},{hi: `बस`, pl: `autobus`, ipa: `/bəs/`},{hi: `ऑटो`, pl: `auto-riksza`, ipa: `/ɔː-ʈoː/`},{hi: `स्टेशन`, pl: `stacja`, ipa: `/sʈeː-ʃən/`},{hi: `टिकट`, pl: `bilet`, ipa: `/ʈɪ-kəʈ/`},{hi: `किराया`, pl: `opłata / fare`, ipa: `/kɪ-raː-jaː/`},{hi: `लाइन`, pl: `linia`, ipa: `/laː-in/`},{hi: `अगला`, pl: `następny`, ipa: `/əg-laː/`},{hi: `रुकना`, pl: `zatrzymać się`, ipa: `/rʊk-naː/`},{hi: `चलना`, pl: `jechać / ruszać`, ipa: `/t͡ʃəl-naː/`}], phrases: [{hi: `मुझे मेट्रो टिकट चाहिए।`, pl: `Potrzebuję biletu na metro.`, ipa: `/mʊ-d͡ʒʱeː meː-ʈroː ʈɪ-kəʈ t͡ʃaː-hi-jeː/`},{hi: `यह कौन सी लाइन है?`, pl: `Która to linia?`, ipa: `/jəh koːn siː laː-in hæː/`},{hi: `अगला स्टेशन कौन सा है?`, pl: `Jaka jest następna stacja?`, ipa: `/əg-laː sʈeː-ʃən koːn saː hæː/`},{hi: `किराया कितना है?`, pl: `Ile wynosi opłata?`, ipa: `/kɪ-raː-jaː kɪt-naː hæː/`},{hi: `यहाँ रोकिए।`, pl: `Proszę zatrzymać tutaj.`, ipa: `/jə-haːn roː-ki-jeː/`},{hi: `क्या आप मेट्रो स्टेशन चलेंगे?`, pl: `Czy pojedzie pan/pani do stacji metra?`, ipa: `/kjaː aːp meː-ʈroː sʈeː-ʃən t͡ʃə-lẽː-geː/`}], grammar: `W pytaniu कौन सा / कौन सी oznacza „który/która”. Forma सा jest używana z rzeczownikami męskimi, a सी z żeńskimi, dlatego कौन सी लाइन, ale कौन सा स्टेशन. To bardzo praktyczny wzór przy pytaniu o opcje.`, practice: [`Poproś o bilet na metro.`,`Zapytaj, która to linia.`,`Zapytaj o następną stację.`,`Powiedz kierowcy, żeby zatrzymał się tutaj.`,`Odegraj krótką rozmowę z kierowcą auto-rikszy.`]},{day: 10, title: `Taksówka i aplikacje przejazdowe`, title_native: `टैक्सी और राइड ऐप`, focus: `Nauczysz się rozmawiać z kierowcą taksówki lub przejazdu z aplikacji. Przyda się to przy dojazdach z hotelu do muzeum, restauracji lub stacji kolejowej.`, vocab: [{hi: `ड्राइवर`, pl: `kierowca`, ipa: `/ɖraː-i-vər/`},{hi: `गाड़ी`, pl: `samochód`, ipa: `/gaː-ɽiː/`},{hi: `पता`, pl: `adres`, ipa: `/pə-taː/`},{hi: `होटल`, pl: `hotel`, ipa: `/hoː-ʈəl/`},{hi: `जल्दी`, pl: `szybko`, ipa: `/d͡ʒəl-diː/`},{hi: `धीरे`, pl: `wolno`, ipa: `/dʱiː-reː/`},{hi: `रास्ता`, pl: `trasa / droga`, ipa: `/raːs-taː/`},{hi: `ट्रैफिक`, pl: `ruch uliczny`, ipa: `/ʈræː-fɪk/`},{hi: `मोबाइल`, pl: `telefon komórkowy`, ipa: `/moː-baː-il/`},{hi: `लोकेशन`, pl: `lokalizacja`, ipa: `/loː-keː-ʃən/`}], phrases: [{hi: `यह मेरा पता है।`, pl: `To jest mój adres.`, ipa: `/jəh meː-raː pə-taː hæː/`},{hi: `लोकेशन यहाँ है।`, pl: `Lokalizacja jest tutaj.`, ipa: `/loː-keː-ʃən jə-haːn hæː/`},{hi: `कृपया धीरे चलाइए।`, pl: `Proszę jechać wolniej.`, ipa: `/krɪ-pə-jaː dʱiː-reː t͡ʃə-laː-i-jeː/`},{hi: `क्या बहुत ट्रैफिक है?`, pl: `Czy jest duży ruch?`, ipa: `/kjaː bə-hʊt ʈræː-fɪk hæː/`},{hi: `मुझे स्टेशन जाना है।`, pl: `Muszę jechać na stację.`, ipa: `/mʊ-d͡ʒʱeː sʈeː-ʃən d͡ʒaː-naː hæː/`},{hi: `यहीं रोक दीजिए।`, pl: `Proszę zatrzymać właśnie tutaj.`, ipa: `/jə-hiːn roːk diː-d͡ʒi-jeː/`}], grammar: `Czasownik चलाना oznacza „prowadzić pojazd”, a चलना może znaczyć „iść, jechać, działać”. Do kierowcy mówisz चलाइए, czyli „proszę prowadzić/jechać”. W podróży wystarczy znać całe zwroty: धीरे चलाइए i यहीं रोक दीजिए.`, practice: [`Powiedz kierowcy, że lokalizacja jest tutaj.`,`Poproś, żeby jechał wolniej.`,`Zapytaj, czy jest duży ruch.`,`Powiedz, że musisz jechać na stację.`,`Przećwicz zakończenie przejazdu: „Proszę zatrzymać tutaj”.`]},{day: 11, title: `Jedzenie i napoje`, title_native: `खाना और पीना`, focus: `Dziś nauczysz się podstawowych słów do zamawiania jedzenia i napojów. Scena pasuje do kawiarni w Delhi, małej restauracji w Jaipurze lub stoiska z chai.`, vocab: [{hi: `खाना`, pl: `jedzenie`, ipa: `/kʰaː-naː/`},{hi: `पानी`, pl: `woda`, ipa: `/paː-niː/`},{hi: `चाय`, pl: `herbata / chai`, ipa: `/t͡ʃaːj/`},{hi: `कॉफी`, pl: `kawa`, ipa: `/kɔː-fiː/`},{hi: `दूध`, pl: `mleko`, ipa: `/duːdʱ/`},{hi: `चीनी`, pl: `cukier`, ipa: `/t͡ʃiː-niː/`},{hi: `रोटी`, pl: `chlebek roti`, ipa: `/roː-ʈiː/`},{hi: `चावल`, pl: `ryż`, ipa: `/t͡ʃaː-ʋəl/`},{hi: `सब्ज़ी`, pl: `warzywa / danie warzywne`, ipa: `/səb-ziː/`},{hi: `मसाला`, pl: `przyprawa / mieszanka przypraw`, ipa: `/mə-saː-laː/`}], phrases: [{hi: `मुझे पानी चाहिए।`, pl: `Potrzebuję wody.`, ipa: `/mʊ-d͡ʒʱeː paː-niː t͡ʃaː-hi-jeː/`},{hi: `एक चाय, कृपया।`, pl: `Jedną chai, proszę.`, ipa: `/eːk t͡ʃaːj krɪ-pə-jaː/`},{hi: `बिना चीनी।`, pl: `Bez cukru.`, ipa: `/bɪ-naː t͡ʃiː-niː/`},{hi: `दूध के साथ।`, pl: `Z mlekiem.`, ipa: `/duːdʱ keː saːtʰ/`},{hi: `यह बहुत अच्छा है।`, pl: `To jest bardzo dobre.`, ipa: `/jəh bə-hʊt ət͡ʃ-t͡ʃʰaː hæː/`},{hi: `क्या खाना मिलेगा?`, pl: `Czy będzie jedzenie?`, ipa: `/kjaː kʰaː-naː mɪ-leː-gaː/`}], grammar: `Zwrot बिना oznacza „bez”, a के साथ oznacza „z”. Możesz powiedzieć बिना चीनी, बिना दूध, albo दूध के साथ. To bardzo przydatne przy zamawianiu napojów i jedzenia.`, practice: [`Zamów jedną chai.`,`Poproś o wodę.`,`Powiedz „bez cukru”.`,`Powiedz, że jedzenie jest bardzo dobre.`,`Ułóż zamówienie: kawa z mlekiem, bez cukru.`]},{day: 12, title: `W restauracji`, title_native: `रेस्तराँ में`, focus: `Nauczysz się zamawiać posiłek w restauracji i pytać o menu. Przyda się w popularnych miejscach w Delhi, Agrze lub Jaipurze.`, vocab: [{hi: `रेस्तराँ`, pl: `restauracja`, ipa: `/res-tə-raːn/`},{hi: `मेन्यू`, pl: `menu`, ipa: `/meː-njuː/`},{hi: `वेटर`, pl: `kelner`, ipa: `/ʋeː-ʈər/`},{hi: `बिल`, pl: `rachunek`, ipa: `/bɪl/`},{hi: `थाली`, pl: `zestaw thali`, ipa: `/tʰaː-liː/`},{hi: `दाल`, pl: `dal / potrawa z soczewicy`, ipa: `/daːl/`},{hi: `नान`, pl: `naan`, ipa: `/naːn/`},{hi: `मसालेदार`, pl: `pikantny / przyprawiony`, ipa: `/mə-saː-leː-daːr/`},{hi: `मीठा`, pl: `słodki`, ipa: `/miː-ʈʰaː/`},{hi: `स्वादिष्ट`, pl: `smaczny`, ipa: `/sʋaː-dɪʂʈ/`}], phrases: [{hi: `मेन्यू दीजिए, कृपया।`, pl: `Proszę podać menu.`, ipa: `/meː-njuː diː-d͡ʒi-jeː krɪ-pə-jaː/`},{hi: `क्या यह मसालेदार है?`, pl: `Czy to jest pikantne?`, ipa: `/kjaː jəh mə-saː-leː-daːr hæː/`},{hi: `मुझे थाली चाहिए।`, pl: `Chciałbym/chciałabym thali.`, ipa: `/mʊ-d͡ʒʱeː tʰaː-liː t͡ʃaː-hi-jeː/`},{hi: `बिल दीजिए।`, pl: `Proszę rachunek.`, ipa: `/bɪl diː-d͡ʒi-jeː/`},{hi: `यह बहुत स्वादिष्ट है।`, pl: `To jest bardzo smaczne.`, ipa: `/jəh bə-hʊt sʋaː-dɪʂʈ hæː/`},{hi: `थोड़ा कम मसाला।`, pl: `Trochę mniej przypraw.`, ipa: `/tʰoː-ɽaː kəm mə-saː-laː/`}], grammar: `दीजिए to bardzo grzeczna forma „proszę dać/podać”. Możesz jej użyć w restauracji: मेन्यू दीजिए, बिल दीजिए, पानी दीजिए. Brzmi uprzejmie i naturalnie w sytuacjach obsługowych.`, practice: [`Poproś o menu.`,`Zapytaj, czy danie jest pikantne.`,`Zamów thali.`,`Poproś o rachunek.`,`Powiedz kelnerowi, że jedzenie jest bardzo smaczne.`]},{day: 13, title: `Preferencje żywieniowe`, title_native: `खाने की पसंद`, focus: `Dziś nauczysz się mówić o tym, czego nie jesz lub czego potrzebujesz w jedzeniu. To ważne w Indiach, gdzie kuchnia bywa pikantna i wiele dań jest wegetariańskich.`, vocab: [{hi: `शाकाहारी`, pl: `wegetariański / wegetarianin`, ipa: `/ʃaː-kaː-haː-riː/`},{hi: `मांस`, pl: `mięso`, ipa: `/maːns/`},{hi: `चिकन`, pl: `kurczak`, ipa: `/t͡ʃɪ-kən/`},{hi: `मछली`, pl: `ryba`, ipa: `/mət͡ʃʰ-liː/`},{hi: `अंडा`, pl: `jajko`, ipa: `/ən-ɖaː/`},{hi: `दूध`, pl: `mleko`, ipa: `/duːdʱ/`},{hi: `दही`, pl: `jogurt`, ipa: `/də-hiː/`},{hi: `मिर्च`, pl: `chili`, ipa: `/mɪrt͡ʃ/`},{hi: `कम`, pl: `mniej`, ipa: `/kəm/`},{hi: `ज़्यादा`, pl: `więcej / dużo`, ipa: `/zjaː-daː/`}], phrases: [{hi: `मैं शाकाहारी हूँ।`, pl: `Jestem wegetarianinem/wegetarianką.`, ipa: `/mæ̃ː ʃaː-kaː-haː-riː huːn/`},{hi: `मैं मांस नहीं खाता।`, pl: `Nie jem mięsa.`, ipa: `/mæ̃ː maːns nə-hiːn kʰaː-taː/`},{hi: `मिर्च कम रखिए।`, pl: `Proszę dać mniej chili.`, ipa: `/mɪrt͡ʃ kəm rəkʰ-i-jeː/`},{hi: `क्या इसमें अंडा है?`, pl: `Czy jest w tym jajko?`, ipa: `/kjaː ɪs-mẽː ən-ɖaː hæː/`},{hi: `क्या यह शाकाहारी है?`, pl: `Czy to jest wegetariańskie?`, ipa: `/kjaː jəh ʃaː-kaː-haː-riː hæː/`},{hi: `मुझे बिना मिर्च चाहिए।`, pl: `Chciałbym/chciałabym bez chili.`, ipa: `/mʊ-d͡ʒʱeː bɪ-naː mɪrt͡ʃ t͡ʃaː-hi-jeː/`}], grammar: `W zdaniu „nie jem” używasz नहीं przed czasownikiem: मैं मांस नहीं खाता। Forma खाता jest męska; kobieta może powiedzieć खाती. W sytuacji podróżnej najważniejsze jest jednak słowo नहीं i jasne wskazanie produktu.`, practice: [`Powiedz, że jesteś wegetarianinem/wegetarianką.`,`Zapytaj, czy danie jest wegetariańskie.`,`Poproś o mniej chili.`,`Zapytaj, czy w daniu jest jajko.`,`Powiedz, że nie jesz mięsa.`]},{day: 14, title: `Zakupy na bazarze`, title_native: `बाज़ार में खरीदारी`, focus: `Nauczysz się pytać o ceny i kupować drobne rzeczy na bazarze. Scena pasuje do Chandni Chowk w Delhi lub kolorowych bazarów w Jaipurze.`, vocab: [{hi: `बाज़ार`, pl: `bazar`, ipa: `/baː-zaːr/`},{hi: `दुकान`, pl: `sklep`, ipa: `/dʊ-kaːn/`},{hi: `कीमत`, pl: `cena`, ipa: `/kiː-mət/`},{hi: `महँगा`, pl: `drogi`, ipa: `/mə-həŋ-gaː/`},{hi: `सस्ता`, pl: `tani`, ipa: `/səs-taː/`},{hi: `कपड़ा`, pl: `tkanina / ubranie`, ipa: `/kəp-ɽaː/`},{hi: `जूते`, pl: `buty`, ipa: `/d͡ʒuː-teː/`},{hi: `बैग`, pl: `torba`, ipa: `/bæːg/`},{hi: `रंग`, pl: `kolor`, ipa: `/rəŋg/`},{hi: `छोटा`, pl: `mały`, ipa: `/t͡ʃʰoː-ʈaː/`}], phrases: [{hi: `यह कितना है?`, pl: `Ile to kosztuje?`, ipa: `/jəh kɪt-naː hæː/`},{hi: `यह बहुत महँगा है।`, pl: `To jest bardzo drogie.`, ipa: `/jəh bə-hʊt mə-həŋ-gaː hæː/`},{hi: `कुछ सस्ता है?`, pl: `Czy jest coś tańszego?`, ipa: `/kʊt͡ʃʰ səs-taː hæː/`},{hi: `मुझे यह चाहिए।`, pl: `Chcę to.`, ipa: `/mʊ-d͡ʒʱeː jəh t͡ʃaː-hi-jeː/`},{hi: `दूसरा रंग है?`, pl: `Czy jest inny kolor?`, ipa: `/duː-sraː rəŋg hæː/`},{hi: `छोटा साइज है?`, pl: `Czy jest mały rozmiar?`, ipa: `/t͡ʃʰoː-ʈaː saː-iz hæː/`}], grammar: `यह oznacza „to” dla rzeczy blisko ciebie. Możesz używać go w sklepie, wskazując przedmiot: यह कितना है? i मुझे यह चाहिए। Przy zakupach gest i kontekst bardzo pomagają, więc krótkie zdania są wystarczające.`, practice: [`Zapytaj o cenę przedmiotu.`,`Powiedz, że coś jest bardzo drogie.`,`Zapytaj o coś tańszego.`,`Poproś o inny kolor.`,`Odegraj krótkie targowanie na bazarze.`]},{day: 15, title: `Kolory, rozmiary i ubrania`, title_native: `रंग, साइज और कपड़े`, focus: `Dziś rozbudujesz język zakupów o kolory i rozmiary. Przyda się przy kupowaniu ubrań, szali, sandałów lub pamiątek.`, vocab: [{hi: `लाल`, pl: `czerwony`, ipa: `/laːl/`},{hi: `नीला`, pl: `niebieski`, ipa: `/niː-laː/`},{hi: `हरा`, pl: `zielony`, ipa: `/hə-raː/`},{hi: `पीला`, pl: `żółty`, ipa: `/piː-laː/`},{hi: `काला`, pl: `czarny`, ipa: `/kaː-laː/`},{hi: `सफेद`, pl: `biały`, ipa: `/sə-pʰeːd/`},{hi: `बड़ा`, pl: `duży`, ipa: `/bə-ɽaː/`},{hi: `छोटा`, pl: `mały`, ipa: `/t͡ʃʰoː-ʈaː/`},{hi: `साइज`, pl: `rozmiar`, ipa: `/saː-iz/`},{hi: `कपड़े`, pl: `ubrania`, ipa: `/kəp-ɽeː/`}], phrases: [{hi: `मुझे नीला रंग चाहिए।`, pl: `Chcę niebieski kolor.`, ipa: `/mʊ-d͡ʒʱeː niː-laː rəŋg t͡ʃaː-hi-jeː/`},{hi: `बड़ा साइज है?`, pl: `Czy jest duży rozmiar?`, ipa: `/bə-ɽaː saː-iz hæː/`},{hi: `छोटा साइज चाहिए।`, pl: `Potrzebuję małego rozmiaru.`, ipa: `/t͡ʃʰoː-ʈaː saː-iz t͡ʃaː-hi-jeː/`},{hi: `क्या यह काला है?`, pl: `Czy to jest czarne?`, ipa: `/kjaː jəh kaː-laː hæː/`},{hi: `सफेद कपड़ा सुंदर है।`, pl: `Biała tkanina jest piękna.`, ipa: `/sə-pʰeːd kəp-ɽaː sʊn-dər hæː/`},{hi: `मुझे यह पसंद है।`, pl: `Podoba mi się to.`, ipa: `/mʊ-d͡ʒʱeː jəh pə-sənd hæː/`}], grammar: `Kolory w hindi często zachowują się jak przymiotniki i mogą zmieniać końcówkę, ale w prostych sytuacjach zakupowych możesz używać podstawowej formy z rzeczownikiem रंग. Na przykład नीला रंग चाहिए jest jasne i naturalne. Słowo पसंद pomaga powiedzieć, co ci się podoba.`, practice: [`Powiedz, że chcesz niebieski kolor.`,`Zapytaj o większy rozmiar.`,`Powiedz, że coś ci się podoba.`,`Nazwij pięć kolorów po hindi.`,`Ułóż dialog w sklepie z ubraniami.`]},{day: 16, title: `Pieniądze i płatność`, title_native: `पैसे और भुगतान`, focus: `Nauczysz się mówić o płaceniu gotówką, kartą i proszeniu o rachunek. Przyda się w sklepach, restauracjach i hotelach w całych Indiach.`, vocab: [{hi: `पैसे`, pl: `pieniądze`, ipa: `/pæː-seː/`},{hi: `रुपये`, pl: `rupie`, ipa: `/rʊ-pə-jeː/`},{hi: `नकद`, pl: `gotówka`, ipa: `/nə-kəd/`},{hi: `कार्ड`, pl: `karta`, ipa: `/kaːrɖ/`},{hi: `भुगतान`, pl: `płatność`, ipa: `/bʱʊg-taːn/`},{hi: `रसीद`, pl: `paragon`, ipa: `/rə-siːd/`},{hi: `बिल`, pl: `rachunek`, ipa: `/bɪl/`},{hi: `छुट्टा`, pl: `drobne / reszta`, ipa: `/t͡ʃʰʊʈ-ʈaː/`},{hi: `कुल`, pl: `razem / suma`, ipa: `/kʊl/`},{hi: `ऑनलाइन`, pl: `online`, ipa: `/ɔn-laː-in/`}], phrases: [{hi: `कार्ड चलेगा?`, pl: `Czy karta zadziała / można kartą?`, ipa: `/kaːrɖ t͡ʃə-leː-gaː/`},{hi: `मैं नकद दूँगा।`, pl: `Zapłacę gotówką.`, ipa: `/mæ̃ː nə-kəd duːŋ-gaː/`},{hi: `रसीद दीजिए।`, pl: `Proszę paragon.`, ipa: `/rə-siːd diː-d͡ʒi-jeː/`},{hi: `कुल कितना है?`, pl: `Ile razem?`, ipa: `/kʊl kɪt-naː hæː/`},{hi: `छुट्टा है?`, pl: `Czy ma pan/pani drobne?`, ipa: `/t͡ʃʰʊʈ-ʈaː hæː/`},{hi: `भुगतान हो गया।`, pl: `Płatność zakończona.`, ipa: `/bʱʊg-taːn hoː gə-jaː/`}], grammar: `कार्ड चलेगा? to bardzo potoczny i praktyczny sposób zapytania, czy można zapłacić kartą. Dosłownie znaczy „czy karta pójdzie/zadziała?”. W Indiach usłyszysz też pytania o płatność online lub przez UPI, ale karta i gotówka nadal są bardzo użyteczne dla turysty.`, practice: [`Zapytaj, czy można zapłacić kartą.`,`Powiedz, że zapłacisz gotówką.`,`Poproś o paragon.`,`Zapytaj o sumę rachunku.`,`Przećwicz rozmowę przy kasie w sklepie.`]},{day: 17, title: `Czas i godziny`, title_native: `समय और घंटे`, focus: `Dziś nauczysz się pytać o godzinę, godziny otwarcia i czas odjazdu. Przyda się przy muzeach, pociągach, restauracjach i wycieczkach.`, vocab: [{hi: `समय`, pl: `czas`, ipa: `/sə-məj/`},{hi: `घंटा`, pl: `godzina`, ipa: `/gʱən-ʈaː/`},{hi: `मिनट`, pl: `minuta`, ipa: `/mɪ-nəʈ/`},{hi: `सुबह`, pl: `rano`, ipa: `/sʊ-bəh/`},{hi: `दोपहर`, pl: `południe / popołudnie`, ipa: `/doː-pə-hər/`},{hi: `शाम`, pl: `wieczór`, ipa: `/ʃaːm/`},{hi: `रात`, pl: `noc`, ipa: `/raːt/`},{hi: `आज`, pl: `dziś`, ipa: `/aːd͡ʒ/`},{hi: `कल`, pl: `jutro / wczoraj`, ipa: `/kəl/`},{hi: `अभी`, pl: `teraz`, ipa: `/ə-bʱiː/`}], phrases: [{hi: `अभी समय क्या है?`, pl: `Która jest teraz godzina?`, ipa: `/ə-bʱiː sə-məj kjaː hæː/`},{hi: `यह कब खुलता है?`, pl: `Kiedy to się otwiera?`, ipa: `/jəh kəb kʰul-taː hæː/`},{hi: `यह कब बंद होता है?`, pl: `Kiedy to się zamyka?`, ipa: `/jəh kəb bənd hoː-taː hæː/`},{hi: `ट्रेन कितने बजे है?`, pl: `O której jest pociąg?`, ipa: `/ʈreːn kɪt-neː bəd͡ʒeː hæː/`},{hi: `मैं सुबह आऊँगा।`, pl: `Przyjdę rano.`, ipa: `/mæ̃ː sʊ-bəh aː-uːŋ-gaː/`},{hi: `शाम को मिलेंगे।`, pl: `Spotkamy się wieczorem.`, ipa: `/ʃaːm koː mɪ-leːŋ-geː/`}], grammar: `Zwrot कितने बजे oznacza „o której godzinie”. Możesz zapytać ट्रेन कितने बजे है? albo बस कितने बजे है? Słowo को po porze dnia, jak शाम को, pomaga powiedzieć „wieczorem”.`, practice: [`Zapytaj, która jest godzina.`,`Zapytaj, o której jest pociąg.`,`Zapytaj, kiedy muzeum się otwiera.`,`Powiedz, że przyjdziesz rano.`,`Ułóż plan dnia z trzema porami: rano, popołudnie, wieczór.`]},{day: 18, title: `Dni, rezerwacje i plany`, title_native: `दिन, बुकिंग और योजना`, focus: `Nauczysz się mówić o dniach tygodnia i prostych planach. To przydatne przy rezerwacji wycieczek, hoteli i biletów.`, vocab: [{hi: `सोमवार`, pl: `poniedziałek`, ipa: `/soːm-vaːr/`},{hi: `मंगलवार`, pl: `wtorek`, ipa: `/məŋ-gəl-vaːr/`},{hi: `बुधवार`, pl: `środa`, ipa: `/bʊdʱ-vaːr/`},{hi: `गुरुवार`, pl: `czwartek`, ipa: `/gʊ-ru-vaːr/`},{hi: `शुक्रवार`, pl: `piątek`, ipa: `/ʃʊ-krə-vaːr/`},{hi: `शनिवार`, pl: `sobota`, ipa: `/ʃə-ni-vaːr/`},{hi: `रविवार`, pl: `niedziela`, ipa: `/rə-vi-vaːr/`},{hi: `योजना`, pl: `plan`, ipa: `/joː-d͡ʒə-naː/`},{hi: `बुक करना`, pl: `rezerwować`, ipa: `/bʊk kər-naː/`},{hi: `यात्रा`, pl: `podróż`, ipa: `/jaː-traː/`}], phrases: [{hi: `मुझे सोमवार के लिए बुकिंग चाहिए।`, pl: `Potrzebuję rezerwacji na poniedziałek.`, ipa: `/mʊ-d͡ʒʱeː soːm-vaːr keː li-jeː bʊ-kɪŋ t͡ʃaː-hi-jeː/`},{hi: `हम शुक्रवार को आएँगे।`, pl: `Przyjedziemy w piątek.`, ipa: `/həm ʃʊ-krə-vaːr koː aː-ẽː-geː/`},{hi: `रविवार को बंद है।`, pl: `W niedzielę jest zamknięte.`, ipa: `/rə-vi-vaːr koː bənd hæː/`},{hi: `क्या शनिवार को जगह है?`, pl: `Czy jest miejsce w sobotę?`, ipa: `/kjaː ʃə-ni-vaːr koː d͡ʒə-gəh hæː/`},{hi: `मेरी यात्रा कल है।`, pl: `Moja podróż jest jutro.`, ipa: `/meː-riː jaː-traː kəl hæː/`},{hi: `आज मेरी योजना बदल गई।`, pl: `Dziś mój plan się zmienił.`, ipa: `/aːd͡ʒ meː-riː joː-d͡ʒə-naː bə-dəl gə-iː/`}], grammar: `Słowo कल jest szczególne, bo może znaczyć „jutro” albo „wczoraj”. Kontekst zwykle wyjaśnia znaczenie. Jeśli chcesz uniknąć nieporozumienia, możesz użyć आने वाला कल dla „jutro”, ale w podróży często wystarczy gest lub data.`, practice: [`Wymień dni tygodnia po hindi.`,`Powiedz, że przyjedziesz w piątek.`,`Zapytaj o miejsce w sobotę.`,`Powiedz, że rezerwacja jest na poniedziałek.`,`Ułóż krótką rozmowę o planie wycieczki.`]},{day: 19, title: `Pociąg i dworzec`, title_native: `ट्रेन और रेलवे स्टेशन`, focus: `Indie mają rozbudowaną sieć kolejową, więc dziś poznasz słowa potrzebne na dworcu. Nauczysz się pytać o peron, bilet i godzinę odjazdu.`, vocab: [{hi: `ट्रेन`, pl: `pociąg`, ipa: `/ʈreːn/`},{hi: `रेलवे स्टेशन`, pl: `dworzec kolejowy`, ipa: `/reːl-veː sʈeː-ʃən/`},{hi: `प्लेटफॉर्म`, pl: `peron`, ipa: `/pleːʈ-fɔːrm/`},{hi: `टिकट`, pl: `bilet`, ipa: `/ʈɪ-kəʈ/`},{hi: `सीट`, pl: `miejsce siedzące`, ipa: `/siːʈ/`},{hi: `डिब्बा`, pl: `wagon`, ipa: `/ɖɪb-baː/`},{hi: `समय`, pl: `czas`, ipa: `/sə-məj/`},{hi: `देरी`, pl: `opóźnienie`, ipa: `/deː-riː/`},{hi: `रद्द`, pl: `odwołany`, ipa: `/rəd̪d̪/`},{hi: `यात्री`, pl: `pasażer`, ipa: `/jaː-triː/`}], phrases: [{hi: `प्लेटफॉर्म नंबर क्या है?`, pl: `Jaki jest numer peronu?`, ipa: `/pleːʈ-fɔːrm nəm-bər kjaː hæː/`},{hi: `मेरी सीट कहाँ है?`, pl: `Gdzie jest moje miejsce?`, ipa: `/meː-riː siːʈ kə-haːn hæː/`},{hi: `ट्रेन देर से है।`, pl: `Pociąg jest opóźniony.`, ipa: `/ʈreːn deːr seː hæː/`},{hi: `क्या यह ट्रेन आगरा जाती है?`, pl: `Czy ten pociąg jedzie do Agry?`, ipa: `/kjaː jəh ʈreːn aː-graː d͡ʒaː-tiː hæː/`},{hi: `मुझे दो टिकट चाहिए।`, pl: `Potrzebuję dwóch biletów.`, ipa: `/mʊ-d͡ʒʱeː doː ʈɪ-kəʈ t͡ʃaː-hi-jeː/`},{hi: `डिब्बा कहाँ है?`, pl: `Gdzie jest wagon?`, ipa: `/ɖɪb-baː kə-haːn hæː/`}], grammar: `Gdy pytasz, czy pociąg jedzie do danego miasta, użyj wzoru: क्या यह ट्रेन [miasto] जाती है? Forma जाती है pasuje do ट्रेन, bo jest gramatycznie żeńska. Ten gotowy wzór jest bardzo użyteczny na dworcu.`, practice: [`Zapytaj o numer peronu.`,`Zapytaj, czy pociąg jedzie do Agry.`,`Powiedz, że pociąg jest opóźniony.`,`Poproś o dwa bilety.`,`Odegraj scenkę szukania wagonu i miejsca.`]},{day: 20, title: `Zwiedzanie i bilety`, title_native: `घूमना और टिकट`, focus: `Nauczysz się kupować bilety do zabytków i pytać o zwiedzanie. Scena pasuje do Taj Mahal w Agrze, Fortu Amber w Jaipurze lub muzeum w Delhi.`, vocab: [{hi: `घूमना`, pl: `zwiedzać / spacerować`, ipa: `/gʱuːm-naː/`},{hi: `टिकट`, pl: `bilet`, ipa: `/ʈɪ-kəʈ/`},{hi: `किला`, pl: `fort`, ipa: `/kɪ-laː/`},{hi: `संग्रहालय`, pl: `muzeum`, ipa: `/səŋ-graː-hə-laːj/`},{hi: `मंदिर`, pl: `świątynia`, ipa: `/mən-dɪr/`},{hi: `गाइड`, pl: `przewodnik`, ipa: `/gaː-iɖ/`},{hi: `फोटो`, pl: `zdjęcie`, ipa: `/pʰoː-ʈoː/`},{hi: `अनुमति`, pl: `pozwolenie`, ipa: `/ə-nʊ-mə-tiː/`},{hi: `प्रवेश`, pl: `wejście`, ipa: `/prə-veːʃ/`},{hi: `विदेशी`, pl: `obcokrajowiec`, ipa: `/ʋɪ-deː-ʃiː/`}], phrases: [{hi: `दो टिकट दीजिए।`, pl: `Proszę dwa bilety.`, ipa: `/doː ʈɪ-kəʈ diː-d͡ʒi-jeː/`},{hi: `प्रवेश कहाँ है?`, pl: `Gdzie jest wejście?`, ipa: `/prə-veːʃ kə-haːn hæː/`},{hi: `क्या फोटो लेना मना है?`, pl: `Czy robienie zdjęć jest zabronione?`, ipa: `/kjaː pʰoː-ʈoː leː-naː mə-naː hæː/`},{hi: `गाइड चाहिए?`, pl: `Czy potrzebny jest przewodnik?`, ipa: `/gaː-iɖ t͡ʃaː-hi-jeː/`},{hi: `विदेशी टिकट कितना है?`, pl: `Ile kosztuje bilet dla obcokrajowca?`, ipa: `/ʋɪ-deː-ʃiː ʈɪ-kəʈ kɪt-naː hæː/`},{hi: `हम घूमना चाहते हैं।`, pl: `Chcemy zwiedzać.`, ipa: `/həm gʱuːm-naː t͡ʃaːh-teː hæːn/`}], grammar: `चाहते हैं oznacza „chcemy” lub „chcą”, zależnie od podmiotu. हम घूमना चाहते हैं to „chcemy zwiedzać”. Dla „ja chcę” możesz powiedzieć मैं घूमना चाहता हूँ, a kobieta: मैं घूमना चाहती हूँ.`, practice: [`Poproś o dwa bilety.`,`Zapytaj, gdzie jest wejście.`,`Zapytaj, czy można robić zdjęcia.`,`Powiedz, że chcecie zwiedzać.`,`Zapytaj o cenę biletu dla obcokrajowca.`]},{day: 21, title: `Zdrowie i apteka`, title_native: `स्वास्थ्य और दवा की दुकान`, focus: `Dziś poznasz zwroty potrzebne w aptece lub przy drobnych problemach zdrowotnych. To ważne podczas podróży w upale, po długim locie lub przy zmianie jedzenia.`, vocab: [{hi: `दवा`, pl: `lekarstwo`, ipa: `/də-vaː/`},{hi: `दवा की दुकान`, pl: `apteka`, ipa: `/də-vaː kiː dʊ-kaːn/`},{hi: `डॉक्टर`, pl: `lekarz`, ipa: `/ɖɔk-ʈər/`},{hi: `दर्द`, pl: `ból`, ipa: `/dərd/`},{hi: `सिर`, pl: `głowa`, ipa: `/sɪr/`},{hi: `पेट`, pl: `brzuch`, ipa: `/peːʈ/`},{hi: `बुखार`, pl: `gorączka`, ipa: `/bʊ-kʰaːr/`},{hi: `खाँसी`, pl: `kaszel`, ipa: `/kʰaːn-siː/`},{hi: `पानी`, pl: `woda`, ipa: `/paː-niː/`},{hi: `आराम`, pl: `odpoczynek`, ipa: `/aː-raːm/`}], phrases: [{hi: `मुझे सिर दर्द है।`, pl: `Boli mnie głowa.`, ipa: `/mʊ-d͡ʒʱeː sɪr dərd hæː/`},{hi: `मुझे पेट दर्द है।`, pl: `Boli mnie brzuch.`, ipa: `/mʊ-d͡ʒʱeː peːʈ dərd hæː/`},{hi: `दवा चाहिए।`, pl: `Potrzebuję lekarstwa.`, ipa: `/də-vaː t͡ʃaː-hi-jeː/`},{hi: `दवा की दुकान कहाँ है?`, pl: `Gdzie jest apteka?`, ipa: `/də-vaː kiː dʊ-kaːn kə-haːn hæː/`},{hi: `क्या डॉक्टर है?`, pl: `Czy jest lekarz?`, ipa: `/kjaː ɖɔk-ʈər hæː/`},{hi: `मुझे बुखार है।`, pl: `Mam gorączkę.`, ipa: `/mʊ-d͡ʒʱeː bʊ-kʰaːr hæː/`}], grammar: `W hindi ból wyraża się często konstrukcją मुझे ... दर्द है, czyli „mam ból ...”. Możesz wstawić część ciała: सिर, पेट, दाँत. To bardzo praktyczny wzór w aptece.`, practice: [`Powiedz, że boli cię głowa.`,`Powiedz, że boli cię brzuch.`,`Zapytaj, gdzie jest apteka.`,`Powiedz, że potrzebujesz lekarstwa.`,`Odegraj rozmowę z farmaceutą.`]},{day: 22, title: `Nagłe sytuacje`, title_native: `आपात स्थिति`, focus: `Nauczysz się podstawowych zwrotów alarmowych i sposobów proszenia o pilną pomoc. To słownictwo warto znać nawet wtedy, gdy masz nadzieję nigdy go nie użyć.`, vocab: [{hi: `आपात स्थिति`, pl: `nagła sytuacja`, ipa: `/aː-paːt sʈʰɪ-tiː/`},{hi: `पुलिस`, pl: `policja`, ipa: `/pʊ-lɪs/`},{hi: `अस्पताल`, pl: `szpital`, ipa: `/əs-pə-taːl/`},{hi: `मदद`, pl: `pomoc`, ipa: `/mə-dəd/`},{hi: `खतरा`, pl: `niebezpieczeństwo`, ipa: `/kʰə-traː/`},{hi: `चोरी`, pl: `kradzież`, ipa: `/t͡ʃoː-riː/`},{hi: `पासपोर्ट`, pl: `paszport`, ipa: `/paːs-poːrʈ/`},{hi: `खो गया`, pl: `zgubiło się`, ipa: `/kʰoː gə-jaː/`},{hi: `जल्दी`, pl: `szybko`, ipa: `/d͡ʒəl-diː/`},{hi: `फोन`, pl: `telefon`, ipa: `/pʰoːn/`}], phrases: [{hi: `मदद!`, pl: `Pomocy!`, ipa: `/mə-dəd/`},{hi: `पुलिस को बुलाइए।`, pl: `Proszę wezwać policję.`, ipa: `/pʊ-lɪs koː bʊ-laː-i-jeː/`},{hi: `मुझे अस्पताल जाना है।`, pl: `Muszę jechać do szpitala.`, ipa: `/mʊ-d͡ʒʱeː əs-pə-taːl d͡ʒaː-naː hæː/`},{hi: `मेरा पासपोर्ट खो गया है।`, pl: `Zgubiłem/zgubiłam paszport.`, ipa: `/meː-raː paːs-poːrʈ kʰoː gə-jaː hæː/`},{hi: `जल्दी आइए।`, pl: `Proszę szybko przyjść.`, ipa: `/d͡ʒəl-diː aː-i-jeː/`},{hi: `फोन करिए, कृपया।`, pl: `Proszę zadzwonić.`, ipa: `/pʰoːn kə-ri-jeː krɪ-pə-jaː/`}], grammar: `खो गया है oznacza „zgubiło się” lub „zostało zgubione”. Dla rzeczy męskiej, jak पासपोर्ट, użyjesz गया; dla żeńskiej można usłyszeć गई. W nagłej sytuacji najważniejsza jest jasność: मेरा पासपोर्ट खो गया है.`, practice: [`Powiedz po hindi „Pomocy!”.`,`Poproś o wezwanie policji.`,`Powiedz, że musisz jechać do szpitala.`,`Powiedz, że zgubiłeś paszport.`,`Przećwicz spokojne, wyraźne wypowiedzenie trzech zdań alarmowych.`]},{day: 23, title: `Pogoda i ubranie`, title_native: `मौसम और कपड़े`, focus: `Dziś nauczysz się mówić o pogodzie, upale, deszczu i tym, czego potrzebujesz. To praktyczne podczas monsunu, upałów w Delhi lub chłodniejszych wieczorów w północnych Indiach.`, vocab: [{hi: `मौसम`, pl: `pogoda`, ipa: `/mɔː-səm/`},{hi: `गरम`, pl: `gorący / ciepły`, ipa: `/gə-rəm/`},{hi: `ठंडा`, pl: `zimny / chłodny`, ipa: `/ʈʰən-ɖaː/`},{hi: `बारिश`, pl: `deszcz`, ipa: `/baː-rɪʃ/`},{hi: `धूप`, pl: `słońce / nasłonecznienie`, ipa: `/dʱuːp/`},{hi: `हवा`, pl: `wiatr / powietrze`, ipa: `/hə-ʋaː/`},{hi: `छाता`, pl: `parasol`, ipa: `/t͡ʃʰaː-taː/`},{hi: `पानी`, pl: `woda`, ipa: `/paː-niː/`},{hi: `कपड़े`, pl: `ubrania`, ipa: `/kəp-ɽeː/`},{hi: `हल्का`, pl: `lekki`, ipa: `/həl-kaː/`}], phrases: [{hi: `आज बहुत गरमी है।`, pl: `Dziś jest bardzo gorąco.`, ipa: `/aːd͡ʒ bə-hʊt gər-miː hæː/`},{hi: `बारिश हो रही है।`, pl: `Pada deszcz.`, ipa: `/baː-rɪʃ hoː rə-hiː hæː/`},{hi: `मुझे पानी चाहिए।`, pl: `Potrzebuję wody.`, ipa: `/mʊ-d͡ʒʱeː paː-niː t͡ʃaː-hi-jeː/`},{hi: `छाता चाहिए।`, pl: `Potrzebny jest parasol.`, ipa: `/t͡ʃʰaː-taː t͡ʃaː-hi-jeː/`},{hi: `मौसम कैसा है?`, pl: `Jaka jest pogoda?`, ipa: `/mɔː-səm kæː-saː hæː/`},{hi: `हल्के कपड़े पहनिए।`, pl: `Proszę założyć lekkie ubrania.`, ipa: `/həl-keː kəp-ɽeː pə-hə-ni-jeː/`}], grammar: `Zwrot हो रही है opisuje czynność trwającą dla rzeczownika żeńskiego, jak बारिश. बारिश हो रही है znaczy „deszcz się dzieje”, czyli „pada”. Nie musisz analizować całej struktury, ale warto zapamiętać to jako gotową frazę.`, practice: [`Powiedz, że dziś jest bardzo gorąco.`,`Powiedz, że pada deszcz.`,`Zapytaj o pogodę.`,`Poproś o wodę.`,`Ułóż krótką rozmowę o tym, czy trzeba wziąć parasol.`]},{day: 24, title: `Telefon, internet i problemy techniczne`, title_native: `फोन, इंटरनेट और तकनीकी समस्या`, focus: `Nauczysz się pytać o Wi-Fi, kartę SIM i ładowarkę. To przydatne w hotelu, kawiarni, sklepie z telefonami i na lotnisku.`, vocab: [{hi: `फोन`, pl: `telefon`, ipa: `/pʰoːn/`},{hi: `मोबाइल`, pl: `telefon komórkowy`, ipa: `/moː-baː-il/`},{hi: `इंटरनेट`, pl: `internet`, ipa: `/ɪn-ʈər-neːʈ/`},{hi: `वाई-फाई`, pl: `Wi-Fi`, ipa: `/ʋaː-iː pʰaː-iː/`},{hi: `पासवर्ड`, pl: `hasło`, ipa: `/paːs-vərɖ/`},{hi: `सिम कार्ड`, pl: `karta SIM`, ipa: `/sɪm kaːrɖ/`},{hi: `चार्जर`, pl: `ładowarka`, ipa: `/t͡ʃaːr-d͡ʒər/`},{hi: `बैटरी`, pl: `bateria`, ipa: `/bæː-ʈə-riː/`},{hi: `काम करना`, pl: `działać`, ipa: `/kaːm kər-naː/`},{hi: `समस्या`, pl: `problem`, ipa: `/sə-məs-jaː/`}], phrases: [{hi: `वाई-फाई पासवर्ड क्या है?`, pl: `Jakie jest hasło do Wi-Fi?`, ipa: `/ʋaː-iː pʰaː-iː paːs-vərɖ kjaː hæː/`},{hi: `मेरा फोन काम नहीं कर रहा है।`, pl: `Mój telefon nie działa.`, ipa: `/meː-raː pʰoːn kaːm nə-hiːn kər rə-haː hæː/`},{hi: `मुझे सिम कार्ड चाहिए।`, pl: `Potrzebuję karty SIM.`, ipa: `/mʊ-d͡ʒʱeː sɪm kaːrɖ t͡ʃaː-hi-jeː/`},{hi: `चार्जर है?`, pl: `Czy jest ładowarka?`, ipa: `/t͡ʃaːr-d͡ʒər hæː/`},{hi: `बैटरी खत्म हो गई।`, pl: `Bateria się skończyła.`, ipa: `/bæː-ʈə-riː kʰə-təm hoː gə-iː/`},{hi: `इंटरनेट धीमा है।`, pl: `Internet jest wolny.`, ipa: `/ɪn-ʈər-neːʈ dʱiː-maː hæː/`}], grammar: `काम नहीं कर रहा है oznacza „nie działa” albo „nie pracuje”. Możesz używać tego wzoru z rzeczami: फोन, इंटरनेट, कार्ड. W codziennej rozmowie to bardzo naturalny sposób zgłaszania problemu.`, practice: [`Zapytaj o hasło do Wi-Fi.`,`Powiedz, że telefon nie działa.`,`Poproś o kartę SIM.`,`Zapytaj, czy jest ładowarka.`,`Powiedz, że internet jest wolny.`]},{day: 25, title: `Małe rozmowy z mieszkańcami`, title_native: `स्थानीय लोगों से छोटी बातचीत`, focus: `Dziś nauczysz się prostych zdań do uprzejmej rozmowy z mieszkańcami. Przyda się w pociągu, kawiarni, podczas wycieczki lub w kolejce.`, vocab: [{hi: `अच्छा`, pl: `dobry / dobrze`, ipa: `/ət͡ʃ-t͡ʃʰaː/`},{hi: `सुंदर`, pl: `piękny`, ipa: `/sʊn-dər/`},{hi: `शहर`, pl: `miasto`, ipa: `/ʃə-hər/`},{hi: `लोग`, pl: `ludzie`, ipa: `/loːg/`},{hi: `परिवार`, pl: `rodzina`, ipa: `/pə-ri-vaːr/`},{hi: `काम`, pl: `praca`, ipa: `/kaːm/`},{hi: `यात्रा`, pl: `podróż`, ipa: `/jaː-traː/`},{hi: `पहली बार`, pl: `pierwszy raz`, ipa: `/pə-hliː baːr/`},{hi: `पसंद`, pl: `lubienie / upodobanie`, ipa: `/pə-sənd/`},{hi: `बहुत`, pl: `bardzo`, ipa: `/bə-hʊt/`}], phrases: [{hi: `यह शहर बहुत सुंदर है।`, pl: `To miasto jest bardzo piękne.`, ipa: `/jəh ʃə-hər bə-hʊt sʊn-dər hæː/`},{hi: `मैं पहली बार भारत आया हूँ।`, pl: `Jestem w Indiach pierwszy raz.`, ipa: `/mæ̃ː pə-hliː baːr bʱaː-rət aː-jaː huːn/`},{hi: `मुझे यहाँ पसंद है।`, pl: `Podoba mi się tutaj.`, ipa: `/mʊ-d͡ʒʱeː jə-haːn pə-sənd hæː/`},{hi: `आपका शहर अच्छा है।`, pl: `Pana/pani miasto jest fajne.`, ipa: `/aːp-kaː ʃə-hər ət͡ʃ-t͡ʃʰaː hæː/`},{hi: `आप क्या काम करते हैं?`, pl: `Czym się pan/pani zajmuje?`, ipa: `/aːp kjaː kaːm kər-teː hæːn/`},{hi: `मेरी यात्रा अच्छी है।`, pl: `Moja podróż jest dobra.`, ipa: `/meː-riː jaː-traː ət͡ʃ-t͡ʃʰiː hæː/`}], grammar: `मुझे ... पसंद है oznacza „podoba mi się...” albo „lubię...”. Możesz powiedzieć मुझे चाय पसंद है, मुझे यह शहर पसंद है, मुझे यहाँ पसंद है. To naturalny wzór do miłych rozmów.`, practice: [`Powiedz, że miasto jest piękne.`,`Powiedz, że jesteś w Indiach pierwszy raz.`,`Powiedz, że podoba ci się tutaj.`,`Zapytaj kogoś, czym się zajmuje.`,`Ułóż krótką przyjazną rozmowę w pociągu.`]},{day: 26, title: `Zaproszenia i spotkania`, title_native: `निमंत्रण और मुलाकात`, focus: `Nauczysz się umawiać na spotkanie, przyjmować lub odmawiać zaproszenia. To przydatne przy poznawaniu ludzi w hostelu, na kursie gotowania lub podczas lokalnej wycieczki.`, vocab: [{hi: `मिलना`, pl: `spotykać się`, ipa: `/mɪl-naː/`},{hi: `निमंत्रण`, pl: `zaproszenie`, ipa: `/nɪ-mən-trən/`},{hi: `साथ`, pl: `razem / z`, ipa: `/saːtʰ/`},{hi: `चलिए`, pl: `chodźmy / proszę iść`, ipa: `/t͡ʃə-li-jeː/`},{hi: `आज`, pl: `dziś`, ipa: `/aːd͡ʒ/`},{hi: `कल`, pl: `jutro / wczoraj`, ipa: `/kəl/`},{hi: `समय`, pl: `czas`, ipa: `/sə-məj/`},{hi: `ठीक`, pl: `dobrze / pasuje`, ipa: `/ʈʰiːk/`},{hi: `माफ़ कीजिए`, pl: `przepraszam`, ipa: `/maːf kiː-d͡ʒi-jeː/`},{hi: `शायद`, pl: `może`, ipa: `/ʃaː-jəd/`}], phrases: [{hi: `क्या हम शाम को मिल सकते हैं?`, pl: `Czy możemy spotkać się wieczorem?`, ipa: `/kjaː həm ʃaːm koː mɪl sək-teː hæːn/`},{hi: `मेरे साथ चलिए।`, pl: `Proszę iść ze mną.`, ipa: `/meː-reː saːtʰ t͡ʃə-li-jeː/`},{hi: `यह समय ठीक है।`, pl: `Ta godzina pasuje.`, ipa: `/jəh sə-məj ʈʰiːk hæː/`},{hi: `माफ़ कीजिए, मैं नहीं आ सकता।`, pl: `Przepraszam, nie mogę przyjść.`, ipa: `/maːf kiː-d͡ʒi-jeː mæ̃ː nə-hiːn aː sək-taː/`},{hi: `शायद कल।`, pl: `Może jutro.`, ipa: `/ʃaː-jəd kəl/`},{hi: `बहुत अच्छा, मिलते हैं।`, pl: `Świetnie, widzimy się.`, ipa: `/bə-hʊt ət͡ʃ-t͡ʃʰaː mɪl-teː hæːn/`}], grammar: `सकना oznacza „móc”. W zwrocie मिल सकते हैं słyszysz „możemy/można się spotkać”. Dla prostych rozmów zapamiętaj gotowe formuły: आ सकता हूँ, मिल सकते हैं, कर सकते हैं.`, practice: [`Zaproponuj spotkanie wieczorem.`,`Powiedz, że godzina pasuje.`,`Uprzejmie odmów spotkania.`,`Powiedz „może jutro”.`,`Ułóż rozmowę z osobą poznaną na wycieczce.`]},{day: 27, title: `W domu gościnnym i codzienna rutyna`, title_native: `गेस्टहाउस और रोज़मर्रा की दिनचर्या`, focus: `Dziś nauczysz się mówić o prostych codziennych potrzebach w pensjonacie lub hostelu. Przyda się przy pytaniu o pranie, wodę, śniadanie i ciszę nocną.`, vocab: [{hi: `गेस्टहाउस`, pl: `dom gościnny`, ipa: `/gesʈ-haːus/`},{hi: `नाश्ता`, pl: `śniadanie`, ipa: `/naːʃ-taː/`},{hi: `कपड़े धोना`, pl: `prać ubrania`, ipa: `/kəp-ɽeː dʱoː-naː/`},{hi: `साफ़`, pl: `czysty`, ipa: `/saːf/`},{hi: `गंदा`, pl: `brudny`, ipa: `/gən-daː/`},{hi: `तौलिया`, pl: `ręcznik`, ipa: `/tɔː-li-jaː/`},{hi: `पानी`, pl: `woda`, ipa: `/paː-niː/`},{hi: `गरम पानी`, pl: `ciepła woda`, ipa: `/gə-rəm paː-niː/`},{hi: `शांत`, pl: `cichy / spokojny`, ipa: `/ʃaːnt/`},{hi: `कमरा`, pl: `pokój`, ipa: `/kəm-raː/`}], phrases: [{hi: `क्या गरम पानी है?`, pl: `Czy jest ciepła woda?`, ipa: `/kjaː gə-rəm paː-niː hæː/`},{hi: `मुझे साफ़ तौलिया चाहिए।`, pl: `Potrzebuję czystego ręcznika.`, ipa: `/mʊ-d͡ʒʱeː saːf tɔː-li-jaː t͡ʃaː-hi-jeː/`},{hi: `नाश्ता कितने बजे है?`, pl: `O której jest śniadanie?`, ipa: `/naːʃ-taː kɪt-neː bəd͡ʒeː hæː/`},{hi: `कमरा शांत है।`, pl: `Pokój jest cichy.`, ipa: `/kəm-raː ʃaːnt hæː/`},{hi: `कपड़े धोने हैं।`, pl: `Trzeba wyprać ubrania.`, ipa: `/kəp-ɽeː dʱoː-neː hæːn/`},{hi: `पानी नहीं आ रहा है।`, pl: `Woda nie leci.`, ipa: `/paː-niː nə-hiːn aː rə-haː hæː/`}], grammar: `Zwrot नहीं आ रहा है oznacza „nie przychodzi/nie leci/nie działa” w zależności od kontekstu. पानी नहीं आ रहा है to naturalny sposób zgłoszenia problemu z wodą. W hotelu możesz podobnie powiedzieć इंटरनेट नहीं आ रहा है.`, practice: [`Zapytaj, czy jest ciepła woda.`,`Poproś o czysty ręcznik.`,`Zapytaj, o której jest śniadanie.`,`Powiedz, że woda nie leci.`,`Ułóż rozmowę z obsługą pensjonatu.`]},{day: 28, title: `Wyrażanie opinii i emocji`, title_native: `राय और भावनाएँ बताना`, focus: `Nauczysz się mówić, co lubisz, co jest trudne, łatwe, piękne lub ciekawe. To pomoże w naturalnych rozmowach po zwiedzaniu i podczas spotkań z mieszkańcami.`, vocab: [{hi: `पसंद`, pl: `lubienie`, ipa: `/pə-sənd/`},{hi: `नापसंद`, pl: `nielubienie`, ipa: `/naː-pə-sənd/`},{hi: `सुंदर`, pl: `piękny`, ipa: `/sʊn-dər/`},{hi: `दिलचस्प`, pl: `interesujący`, ipa: `/dɪl-t͡ʃəsp/`},{hi: `आसान`, pl: `łatwy`, ipa: `/aː-saːn/`},{hi: `मुश्किल`, pl: `trudny`, ipa: `/mʊʃ-kɪl/`},{hi: `खुश`, pl: `szczęśliwy`, ipa: `/kʰʊʃ/`},{hi: `थका हुआ`, pl: `zmęczony`, ipa: `/tʰə-kaː hu-aː/`},{hi: `अच्छा`, pl: `dobry`, ipa: `/ət͡ʃ-t͡ʃʰaː/`},{hi: `बुरा`, pl: `zły`, ipa: `/bʊ-raː/`}], phrases: [{hi: `मुझे यह बहुत पसंद है।`, pl: `Bardzo mi się to podoba.`, ipa: `/mʊ-d͡ʒʱeː jəh bə-hʊt pə-sənd hæː/`},{hi: `यह बहुत दिलचस्प है।`, pl: `To jest bardzo interesujące.`, ipa: `/jəh bə-hʊt dɪl-t͡ʃəsp hæː/`},{hi: `हिंदी मुश्किल है।`, pl: `Hindi jest trudny.`, ipa: `/hɪn-diː mʊʃ-kɪl hæː/`},{hi: `लेकिन मज़ेदार है।`, pl: `Ale jest fajny.`, ipa: `/leː-kɪn mə-zeː-daːr hæː/`},{hi: `मैं थोड़ा थका हुआ हूँ।`, pl: `Jestem trochę zmęczony.`, ipa: `/mæ̃ː tʰoː-ɽaː tʰə-kaː hu-aː huːn/`},{hi: `मैं बहुत खुश हूँ।`, pl: `Jestem bardzo szczęśliwy.`, ipa: `/mæ̃ː bə-hʊt kʰʊʃ huːn/`}], grammar: `लेकिन oznacza „ale” i pozwala łączyć proste opinie: हिंदी मुश्किल है, लेकिन मज़ेदार है. To świetny sposób na naturalniejsze wypowiedzi. Możesz też użyć बहुत i थोड़ा, aby stopniować emocje lub opinie.`, practice: [`Powiedz, że coś bardzo ci się podoba.`,`Powiedz, że hindi jest trudny, ale fajny.`,`Powiedz, że jesteś trochę zmęczony.`,`Powiedz, że jesteś bardzo szczęśliwy.`,`Ułóż trzy zdania opinii po zwiedzaniu zabytku.`]},{day: 29, title: `Rozwiązywanie problemów`, title_native: `समस्याएँ हल करना`, focus: `Dziś połączysz wcześniejsze umiejętności, aby zgłaszać problemy i prosić o rozwiązanie. Sceny obejmują hotel, transport, restaurację i zakupy.`, vocab: [{hi: `समस्या`, pl: `problem`, ipa: `/sə-məs-jaː/`},{hi: `गलत`, pl: `błędny / zły`, ipa: `/gə-lət/`},{hi: `सही`, pl: `poprawny / właściwy`, ipa: `/sə-hiː/`},{hi: `टूटा`, pl: `zepsuty / złamany`, ipa: `/ʈuː-ʈaː/`},{hi: `खराब`, pl: `zepsuty / zły`, ipa: `/kʰə-raːb/`},{hi: `बदलना`, pl: `zmienić / wymienić`, ipa: `/bə-dəl-naː/`},{hi: `वापस`, pl: `z powrotem`, ipa: `/ʋaː-pəs/`},{hi: `देना`, pl: `dać`, ipa: `/deː-naː/`},{hi: `लेना`, pl: `wziąć`, ipa: `/leː-naː/`},{hi: `अभी`, pl: `teraz`, ipa: `/ə-bʱiː/`}], phrases: [{hi: `यह गलत है।`, pl: `To jest błędne.`, ipa: `/jəh gə-lət hæː/`},{hi: `यह सही नहीं है।`, pl: `To nie jest poprawne.`, ipa: `/jəh sə-hiː nə-hiːn hæː/`},{hi: `कमरा खराब है।`, pl: `Pokój jest zły / coś jest nie tak z pokojem.`, ipa: `/kəm-raː kʰə-raːb hæː/`},{hi: `क्या आप इसे बदल सकते हैं?`, pl: `Czy może pan/pani to wymienić?`, ipa: `/kjaː aːp ɪ-seː bə-dəl sək-teː hæːn/`},{hi: `मुझे पैसे वापस चाहिए।`, pl: `Chcę zwrot pieniędzy.`, ipa: `/mʊ-d͡ʒʱeː pæː-seː ʋaː-pəs t͡ʃaː-hi-jeː/`},{hi: `अभी मदद चाहिए।`, pl: `Potrzebuję pomocy teraz.`, ipa: `/ə-bʱiː mə-dəd t͡ʃaː-hi-jeː/`}], grammar: `इसे oznacza „to” jako dopełnienie, czyli „ten przedmiot / tę rzecz”. W zdaniu क्या आप इसे बदल सकते हैं? pytasz „czy może pan/pani to wymienić?”. To bardzo użyteczne w sklepie lub hotelu.`, practice: [`Powiedz, że coś jest niepoprawne.`,`Poproś o wymianę przedmiotu.`,`Powiedz, że pokój ma problem.`,`Poproś o zwrot pieniędzy.`,`Odegraj spokojną rozmowę reklamacyjną.`]},{day: 30, title: `Pełny dzień podróży`, title_native: `यात्रा का पूरा दिन`, focus: `Ostatni dzień łączy wszystko: hotel, transport, jedzenie, zakupy, zwiedzanie i rozmowy. Wyobraź sobie pełny dzień w Delhi lub Jaipurze od śniadania do powrotu do hotelu.`, vocab: [{hi: `यात्रा`, pl: `podróż`, ipa: `/jaː-traː/`},{hi: `सुबह`, pl: `rano`, ipa: `/sʊ-bəh/`},{hi: `नाश्ता`, pl: `śniadanie`, ipa: `/naːʃ-taː/`},{hi: `टैक्सी`, pl: `taksówka`, ipa: `/ʈɛːk-siː/`},{hi: `बाज़ार`, pl: `bazar`, ipa: `/baː-zaːr/`},{hi: `मंदिर`, pl: `świątynia`, ipa: `/mən-dɪr/`},{hi: `रेस्तराँ`, pl: `restauracja`, ipa: `/res-tə-raːn/`},{hi: `होटल`, pl: `hotel`, ipa: `/hoː-ʈəl/`},{hi: `दोस्त`, pl: `przyjaciel`, ipa: `/doːst/`},{hi: `यादगार`, pl: `pamiątka / niezapomniany`, ipa: `/jaːd-gaːr/`}], phrases: [{hi: `आज हमारी यात्रा अच्छी है।`, pl: `Dziś nasza podróż jest dobra.`, ipa: `/aːd͡ʒ hə-maː-riː jaː-traː ət͡ʃ-t͡ʃʰiː hæː/`},{hi: `सुबह नाश्ता करेंगे।`, pl: `Rano zjemy śniadanie.`, ipa: `/sʊ-bəh naːʃ-taː kə-rẽː-geː/`},{hi: `फिर बाज़ार जाएँगे।`, pl: `Potem pójdziemy na bazar.`, ipa: `/pʰir baː-zaːr d͡ʒaː-ẽː-geː/`},{hi: `मुझे एक यादगार चीज़ चाहिए।`, pl: `Chcę jedną pamiątkową rzecz.`, ipa: `/mʊ-d͡ʒʱeː eːk jaːd-gaːr t͡ʃiːz t͡ʃaː-hi-jeː/`},{hi: `शाम को होटल लौटेंगे।`, pl: `Wieczorem wrócimy do hotelu.`, ipa: `/ʃaːm koː hoː-ʈəl lɔː-ʈẽː-geː/`},{hi: `भारत बहुत सुंदर है।`, pl: `Indie są bardzo piękne.`, ipa: `/bʱaː-rət bə-hʊt sʊn-dər hæː/`}], grammar: `Czas przyszły w prostych zdaniach często ma końcówki typu -एँगे lub -करेंगे dla „będziemy”. जाएँगे znaczy „pójdziemy/pojedziemy”, करेंगे znaczy „zrobimy”. W podróży możesz używać gotowych fraz, aby opisać plan dnia.`, practice: [`Opisz po hindi plan poranka: śniadanie i taksówka.`,`Powiedz, że potem pójdziecie na bazar.`,`Poproś o jedną pamiątkę.`,`Powiedz, że wieczorem wrócicie do hotelu.`,`Ułóż pięciozdaniowy opis pełnego dnia podróży w Indiach.`]}];

var CONVERSATIONS_PL_HI = [{id: 1, title: `Zamawianie chai w kawiarni`, scene: `Jesteś w małej kawiarni w Delhi po porannym spacerze. Chcesz zamówić chai bez cukru i zapytać o coś małego do jedzenia.`, lines: [{who: `them`, hi: `नमस्ते, क्या चाहिए?`, pl: `Dzień dobry, co podać?`},{who: `you`, hi: `नमस्ते, एक चाय चाहिए।`, pl: `Dzień dobry, poproszę jedną chai.`},{who: `them`, hi: `चीनी के साथ?`, pl: `Z cukrem?`},{who: `you`, hi: `बिना चीनी, कृपया।`, pl: `Bez cukru, proszę.`},{who: `them`, hi: `दूध चाहिए?`, pl: `Chce pan/pani mleko?`},{who: `you`, hi: `हाँ, दूध के साथ।`, pl: `Tak, z mlekiem.`},{who: `them`, hi: `कुछ खाने के लिए चाहिए?`, pl: `Czy chce pan/pani coś do jedzenia?`},{who: `you`, hi: `क्या समोसा है?`, pl: `Czy jest samosa?`},{who: `them`, hi: `हाँ, गरम समोसा है।`, pl: `Tak, jest gorąca samosa.`},{who: `you`, hi: `एक समोसा भी दीजिए।`, pl: `Proszę też jedną samosę.`},{who: `them`, hi: `कुल पचास रुपये।`, pl: `Razem pięćdziesiąt rupii.`},{who: `you`, hi: `धन्यवाद, यह लीजिए।`, pl: `Dziękuję, proszę bardzo.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Jaipurze. Masz rezerwację i chcesz zapytać o śniadanie oraz Wi-Fi.`, lines: [{who: `them`, hi: `नमस्ते, होटल में आपका स्वागत है।`, pl: `Dzień dobry, witamy w hotelu.`},{who: `you`, hi: `नमस्ते, मेरी बुकिंग है।`, pl: `Dzień dobry, mam rezerwację.`},{who: `them`, hi: `आपका नाम क्या है?`, pl: `Jak się pan/pani nazywa?`},{who: `you`, hi: `मेरा नाम पिओत्र है।`, pl: `Mam na imię Piotr.`},{who: `them`, hi: `जी, आपकी बुकिंग मिल गई।`, pl: `Tak, znalazłem/znalazłam pana/pani rezerwację.`},{who: `you`, hi: `कमरा नंबर क्या है?`, pl: `Jaki jest numer pokoju?`},{who: `them`, hi: `आपका कमरा नंबर दो सौ पाँच है।`, pl: `Pana/pani pokój to numer 205.`},{who: `you`, hi: `क्या नाश्ता शामिल है?`, pl: `Czy śniadanie jest wliczone?`},{who: `them`, hi: `हाँ, नाश्ता सुबह सात बजे है।`, pl: `Tak, śniadanie jest o siódmej rano.`},{who: `you`, hi: `वाई-फाई पासवर्ड क्या है?`, pl: `Jakie jest hasło do Wi-Fi?`},{who: `them`, hi: `पासवर्ड रिसेप्शन पर लिखा है।`, pl: `Hasło jest napisane przy recepcji.`},{who: `you`, hi: `धन्यवाद।`, pl: `Dziękuję.`}]},{id: 3, title: `Pytanie o drogę do bazaru`, scene: `Spacerujesz po Jaipurze i chcesz znaleźć lokalny bazar. Zatrzymujesz przechodnia i pytasz o drogę prostymi, uprzejmymi zdaniami.`, lines: [{who: `you`, hi: `माफ़ कीजिए, बाज़ार कहाँ है?`, pl: `Przepraszam, gdzie jest bazar?`},{who: `them`, hi: `बाज़ार यहाँ से पास है।`, pl: `Bazar jest blisko stąd.`},{who: `you`, hi: `कैसे जाना है?`, pl: `Jak tam dojść?`},{who: `them`, hi: `सीधा जाइए।`, pl: `Proszę iść prosto.`},{who: `you`, hi: `फिर?`, pl: `A potem?`},{who: `them`, hi: `फिर दाएँ मुड़िए।`, pl: `Potem proszę skręcić w prawo.`},{who: `you`, hi: `क्या वह मंदिर के पास है?`, pl: `Czy to jest przy świątyni?`},{who: `them`, hi: `हाँ, मंदिर के पास है।`, pl: `Tak, jest przy świątyni.`},{who: `you`, hi: `कितने मिनट लगेंगे?`, pl: `Ile minut to zajmie?`},{who: `them`, hi: `दस मिनट लगेंगे।`, pl: `Zajmie to dziesięć minut.`},{who: `you`, hi: `बहुत धन्यवाद।`, pl: `Bardzo dziękuję.`},{who: `them`, hi: `कोई बात नहीं।`, pl: `Nie ma za co.`}]},{id: 4, title: `Obiad w restauracji`, scene: `Siadasz w restauracji w Agrze po zwiedzaniu. Chcesz menu, pytasz o ostrość dania i zamawiasz wegetariańskie thali.`, lines: [{who: `them`, hi: `नमस्ते, बैठिए।`, pl: `Dzień dobry, proszę usiąść.`},{who: `you`, hi: `धन्यवाद, मेन्यू दीजिए।`, pl: `Dziękuję, proszę menu.`},{who: `them`, hi: `यह मेन्यू है।`, pl: `Oto menu.`},{who: `you`, hi: `क्या यह थाली शाकाहारी है?`, pl: `Czy to thali jest wegetariańskie?`},{who: `them`, hi: `हाँ, यह शाकाहारी है।`, pl: `Tak, jest wegetariańskie.`},{who: `you`, hi: `क्या यह बहुत मसालेदार है?`, pl: `Czy jest bardzo pikantne?`},{who: `them`, hi: `थोड़ा मसालेदार है।`, pl: `Jest trochę pikantne.`},{who: `you`, hi: `मिर्च कम रखिए, कृपया।`, pl: `Proszę dać mniej chili.`},{who: `them`, hi: `ठीक है, और कुछ?`, pl: `Dobrze, coś jeszcze?`},{who: `you`, hi: `एक पानी भी चाहिए।`, pl: `Poproszę też jedną wodę.`},{who: `them`, hi: `ज़रूर।`, pl: `Oczywiście.`},{who: `you`, hi: `धन्यवाद।`, pl: `Dziękuję.`}]},{id: 5, title: `Kupowanie biletu na metro`, scene: `Jesteś przy kasie metra w Delhi. Chcesz kupić dwa bilety i upewnić się, która linia jedzie do właściwej stacji.`, lines: [{who: `them`, hi: `नमस्ते, कहाँ जाना है?`, pl: `Dzień dobry, dokąd pan/pani jedzie?`},{who: `you`, hi: `मुझे राजीव चौक जाना है।`, pl: `Muszę jechać do Rajiv Chowk.`},{who: `them`, hi: `कितने टिकट चाहिए?`, pl: `Ile biletów potrzeba?`},{who: `you`, hi: `दो टिकट चाहिए।`, pl: `Potrzebuję dwóch biletów.`},{who: `them`, hi: `यह ब्लू लाइन है।`, pl: `To jest niebieska linia.`},{who: `you`, hi: `अगला स्टेशन कौन सा है?`, pl: `Jaka jest następna stacja?`},{who: `them`, hi: `अगला स्टेशन नई दिल्ली है।`, pl: `Następna stacja to New Delhi.`},{who: `you`, hi: `किराया कितना है?`, pl: `Ile wynosi opłata?`},{who: `them`, hi: `साठ रुपये।`, pl: `Sześćdziesiąt rupii.`},{who: `you`, hi: `कार्ड चलेगा?`, pl: `Czy można kartą?`},{who: `them`, hi: `हाँ, कार्ड चलेगा।`, pl: `Tak, można kartą.`},{who: `you`, hi: `धन्यवाद।`, pl: `Dziękuję.`}]},{id: 6, title: `Zakupy pamiątek na bazarze`, scene: `Na bazarze w Jaipurze oglądasz torbę i szal. Chcesz zapytać o cenę, kolor i spróbować grzecznie poprosić o tańszą opcję.`, lines: [{who: `them`, hi: `नमस्ते, आइए।`, pl: `Dzień dobry, proszę podejść.`},{who: `you`, hi: `नमस्ते, यह बैग कितना है?`, pl: `Dzień dobry, ile kosztuje ta torba?`},{who: `them`, hi: `यह आठ सौ रुपये है।`, pl: `To kosztuje osiemset rupii.`},{who: `you`, hi: `यह बहुत महँगा है।`, pl: `To jest bardzo drogie.`},{who: `them`, hi: `अच्छा सामान है।`, pl: `To dobry towar.`},{who: `you`, hi: `कुछ सस्ता है?`, pl: `Czy jest coś tańszego?`},{who: `them`, hi: `यह छोटा बैग पाँच सौ रुपये है।`, pl: `Ta mała torba kosztuje pięćset rupii.`},{who: `you`, hi: `दूसरा रंग है?`, pl: `Czy jest inny kolor?`},{who: `them`, hi: `हाँ, नीला और लाल है।`, pl: `Tak, jest niebieski i czerwony.`},{who: `you`, hi: `मुझे नीला चाहिए।`, pl: `Chcę niebieski.`},{who: `them`, hi: `ठीक है, यह लीजिए।`, pl: `Dobrze, proszę.`},{who: `you`, hi: `धन्यवाद।`, pl: `Dziękuję.`}]},{id: 7, title: `W aptece`, scene: `Po całym dniu zwiedzania boli cię głowa i szukasz apteki. Wchodzisz do małej apteki i prosisz o lekarstwo.`, lines: [{who: `them`, hi: `नमस्ते, क्या समस्या है?`, pl: `Dzień dobry, jaki jest problem?`},{who: `you`, hi: `मुझे सिर दर्द है।`, pl: `Boli mnie głowa.`},{who: `them`, hi: `बुखार है?`, pl: `Czy ma pan/pani gorączkę?`},{who: `you`, hi: `नहीं, बुखार नहीं है।`, pl: `Nie, nie mam gorączki.`},{who: `them`, hi: `आपको दवा चाहिए?`, pl: `Potrzebuje pan/pani lekarstwa?`},{who: `you`, hi: `हाँ, दवा चाहिए।`, pl: `Tak, potrzebuję lekarstwa.`},{who: `them`, hi: `पानी के साथ लीजिए।`, pl: `Proszę wziąć z wodą.`},{who: `you`, hi: `कितनी बार लेना है?`, pl: `Ile razy trzeba brać?`},{who: `them`, hi: `दिन में दो बार।`, pl: `Dwa razy dziennie.`},{who: `you`, hi: `रसीद दीजिए, कृपया।`, pl: `Proszę paragon.`},{who: `them`, hi: `ज़रूर।`, pl: `Oczywiście.`},{who: `you`, hi: `धन्यवाद।`, pl: `Dziękuję.`}]},{id: 8, title: `Mała rozmowa z lokalną osobą`, scene: `Jedziesz pociągiem z Delhi do Agry i rozmawiasz z osobą siedzącą obok. Chcesz powiedzieć, że jesteś z Polski, jesteś w Indiach pierwszy raz i podoba ci się podróż.`, lines: [{who: `you`, hi: `नमस्ते, क्या यह सीट खाली है?`, pl: `Dzień dobry, czy to miejsce jest wolne?`},{who: `them`, hi: `हाँ, बैठिए।`, pl: `Tak, proszę usiąść.`},{who: `you`, hi: `धन्यवाद, मेरा नाम अन्ना है।`, pl: `Dziękuję, mam na imię Anna.`},{who: `them`, hi: `मेरा नाम राहुल है।`, pl: `Mam na imię Rahul.`},{who: `you`, hi: `मैं पोलैंड से हूँ।`, pl: `Jestem z Polski.`},{who: `them`, hi: `बहुत अच्छा, भारत में पहली बार?`, pl: `Bardzo fajnie, pierwszy raz w Indiach?`},{who: `you`, hi: `हाँ, मैं पहली बार भारत आई हूँ।`, pl: `Tak, jestem w Indiach pierwszy raz.`},{who: `them`, hi: `आपको भारत कैसा लगा?`, pl: `Jak podobają się pani Indie?`},{who: `you`, hi: `भारत बहुत सुंदर है।`, pl: `Indie są bardzo piękne.`},{who: `them`, hi: `क्या आपको चाय पसंद है?`, pl: `Czy lubi pani chai?`},{who: `you`, hi: `हाँ, मुझे चाय बहुत पसंद है।`, pl: `Tak, bardzo lubię chai.`},{who: `them`, hi: `आपकी यात्रा अच्छी हो।`, pl: `Życzę dobrej podróży.`}]}];